          <div className="flex justify-center items-center py-20">
            <Loader2 className="w-8 h-8 animate-spin text-[#4D00FF]" />
          </div>
        </div>
      </section>
    );
  }

  if (!featured.length) {
    return (
      <section className="py-12 bg-white">
        <div className="container mx-auto px-6">
