import { Navbar } from "@/components/layout/navbar";
import { Footer } from "@/components/layout/footer";
import { motion } from "framer-motion";
import { useRoute, Link } from "wouter";
import { ArrowUpRight, ArrowLeft, Loader2 } from "lucide-react";
import { useQuery } from "@tanstack/react-query";
import type { BlogPost, Category } from "@shared/schema";
import NotFound from "@/pages/not-found";

const categoryMeta: Record<string, { title: string; description: string }> = {
  "tools": {
    title: "Tools",
    description: "My favorite tools I use every single day. The entire stack.",
  },
  "industry-news": {
    title: "Industry News",
    description: "Insights on industry changes, curated from my LinkedIn.",
  },
  "experiments": {
    title: "Experiments",
    description: "Everything I'm testing right now - SEO experiments, workflows, content frameworks, and monthly reports.",
  },
  "behind-the-work": {
    title: "Behind the Work",
    description: "Debugging, client problem solving, and mid-process thoughts.",
  },
  "personal-notes": {
    title: "Personal Notes",
    description: "Lessons on consulting, productivity, and mindset shifts.",
  }
};

export default function JournalCategory() {
  const [, params] = useRoute("/journal/:category");
  const categorySlug = params?.category;

  const { data: posts, isLoading } = useQuery<BlogPost[]>({
    queryKey: ["/api/blog/posts"],
  });

  const meta = categorySlug ? categoryMeta[categorySlug] : null;

  if (!categorySlug || !meta) {
    return <NotFound />;
  }

  const getReadTime = (content: string | null) => {
    if (!content) return "3 min read";
    const words = content.split(/\s+/).length;
    const minutes = Math.ceil(words / 200);
    return `${minutes} min read`;
  };

  const formatDate = (date: Date | string | null) => {
    if (!date) return "";
    return new Date(date).toLocaleDateString('en-US', { 
      month: 'short', 
      day: 'numeric', 
      year: 'numeric' 
    });
  };

  const categoryPosts = posts || [];

  return (
    <div className="min-h-screen bg-[#FBFCFE] text-[#1B1B1B] font-sans selection:bg-[#4D00FF] selection:text-white">
      <Navbar />

      <section className="pt-40 pb-20 bg-[#FBFCFE]">
        <div className="container mx-auto px-6">
          <Link href="/journal" className="inline-flex items-center text-[#1B1B1B]/60 hover:text-[#4D00FF] mb-8 transition-colors">
            <ArrowLeft className="w-4 h-4 mr-2" />
            Back to Journal
          </Link>
          <motion.div 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
            className="max-w-4xl"
          >
