client/src/index.css.content:
@import "tailwindcss";
@import "tw-animate-css";

@custom-variant dark (&:is(.dark *));

@theme inline {
  --radius-sm: calc(var(--radius) - 4px);
  --radius-md: calc(var(--radius) - 2px);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) + 4px);

  /* Custom Color Palette - High Contrast SarahDigs */
  --color-background: hsl(var(--background));
  --color-foreground: hsl(var(--foreground));

  --color-card: hsl(var(--card));
  --color-card-foreground: hsl(var(--card-foreground));

  --color-popover: hsl(var(--popover));
  --color-popover-foreground: hsl(var(--popover-foreground));

  --color-primary: hsl(var(--primary));
  --color-primary-foreground: hsl(var(--primary-foreground));

  --color-secondary: hsl(var(--secondary));
  --color-secondary-foreground: hsl(var(--secondary-foreground));

  --color-muted: hsl(var(--muted));
  --color-muted-foreground: hsl(var(--muted-foreground));

  --color-accent: hsl(var(--accent));
  --color-accent-foreground: hsl(var(--accent-foreground));

  --color-destructive: hsl(var(--destructive));
  --color-destructive-foreground: hsl(var(--destructive-foreground));

  --color-border: hsl(var(--border));
  --color-input: hsl(var(--input));
  --color-ring: hsl(var(--ring));

  --font-sans: 'Inter', sans-serif;
  --font-display: 'Syne', sans-serif;

  /* Updated radius to match iOS style (~17.5% feel) */
  --radius: 1rem; 
}

:root {
  /* Light Mode - Default */
  --background: 220 33% 99%; /* #FBFCFE */
  --foreground: 0 0% 11%; /* #1B1B1B */

  --card: 0 0% 100%;
  --card-foreground: 0 0% 11%;

  --popover: 0 0% 100%;
  --popover-foreground: 0 0% 11%;

  --primary: 0 0% 11%;       /* #1B1B1B Buttons */
  --primary-foreground: 0 0% 100%;

  --secondary: 0 0% 11%;    /* #1B1B1B (Dark Section Background) */
  --secondary-foreground: 0 0% 100%; /* White text on secondary */

  --muted: 250 100% 97%; /* #F4F2FF (Light Lavender) */
  --muted-foreground: 0 0% 40%;

  /* Electric Blue #4d00ff */
  --accent: 258 100% 50%;
  --accent-foreground: 0 0% 100%;

  --destructive: 0 84.2% 60.2%;
  --destructive-foreground: 0 0% 98%;

  --border: 0 0% 11%; 
  --input: 0 0% 11%;
  --ring: 0 0% 11%;

  --radius: 1rem;

  /* Custom Brand Colors */
  --brand-green: 132 34% 58%; /* #70B77E */
}

.dark {
  /* Dark Mode - Inverted High Contrast */
  --background: 0 0% 0%;
  --foreground: 0 0% 100%;

  --card: 0 0% 3%;
  --card-foreground: 0 0% 100%;

  --popover: 0 0% 3%;
  --popover-foreground: 0 0% 100%;

  --primary: 0 0% 100%;
  --primary-foreground: 0 0% 0%;

  --secondary: 0 0% 10%;
  --secondary-foreground: 0 0% 100%;

  --muted: 0 0% 10%;
  --muted-foreground: 0 0% 65%;

  /* Electric Blue #4d00ff */
  --accent: 258 100% 50%;
  --accent-foreground: 0 0% 100%;

  --destructive: 0 62.8% 30.6%;
  --destructive-foreground: 0 0% 98%;

  --border: 0 0% 20%;
  --input: 0 0% 20%;
  --ring: 0 0% 100%;
}

@layer base {
  * {
    @apply border-border;
  }
  body {
    @apply font-sans antialiased bg-background text-foreground selection:bg-accent selection:text-accent-foreground;
  }
  h1, h2, h3, h4, h5, h6 {
    @apply font-display font-bold tracking-tight;
  }
}

