export class DatabaseStorage implements IStorage {
  async getUser(userId: string) {
    return db.query.users.findFirst({
      where: eq(users.id, userId),
    });
  }

  async createUser(data: { id: string; email: string; name: string; role: string }) {
    const [user] = await db.insert(users).values(data).returning();
    return user;
  }

  async upsertUser(userData: UpsertUser): Promise<User> {
    const [user] = await db
      .insert(users)
      .values(userData)
      .onConflictDoUpdate({
        target: users.id,
        set: {
          ...userData,
          updatedAt: new Date(),
        },
      })
      .returning();
    return user;
  }

  async getBlogPosts(): Promise<BlogPost[]> {
    try {
      const result = await db.select().from(blogPosts).orderBy(desc(blogPosts.createdAt));
      return Array.isArray(result) ? result : [];
    } catch (error) {
      console.error("Error fetching blog posts:", error);
      return [];
    }
  }

  async getBlogPost(id: string): Promise<BlogPost | undefined> {
    const [post] = await db.select().from(blogPosts).where(eq(blogPosts.id, id));
    return post;
  }

  async getBlogPostBySlug(slug: string): Promise<BlogPost | undefined> {
    const [post] = await db.select().from(blogPosts).where(eq(blogPosts.slug, slug));
    return post;
  }

  async getPublishedBlogPosts(): Promise<BlogPost[]> {
    return await db.select().from(blogPosts)
      .where(eq(blogPosts.status, "published"))
      .orderBy(desc(blogPosts.publishedAt));
  }

  async createBlogPost(post: InsertBlogPost): Promise<BlogPost> {
    const [result] = await db.insert(blogPosts).values(post).returning();
    return result;
  }

  async updateBlogPost(id: string, post: Partial<InsertBlogPost>): Promise<BlogPost> {
    const [result] = await db.update(blogPosts)
      .set({ ...post, updatedAt: new Date() })
      .where(eq(blogPosts.id, id))
      .returning();
    return result;
  }

  async deleteBlogPost(id: string): Promise<void> {
    await db.delete(postCategories).where(eq(postCategories.postId, id));
    await db.delete(postTags).where(eq(postTags.postId, id));
    await db.delete(blogPosts).where(eq(blogPosts.id, id));
  }

  async getCategories(): Promise<Category[]> {
    try {
      const result = await db.select().from(categories);
      return Array.isArray(result) ? result : [];
    } catch (error) {
      console.error("Error fetching categories:", error);
      return [];
    }
  }

  async createCategory(category: InsertCategory): Promise<Category> {
    const [result] = await db.insert(categories).values(category).returning();
    return result;
  }

  async updateCategory(id: string, category: Partial<InsertCategory>): Promise<Category> {
    const [result] = await db.update(categories)
      .set(category)
      .where(eq(categories.id, id))
      .returning();
    return result;
  }

  async deleteCategory(id: string): Promise<void> {
    await db.delete(postCategories).where(eq(postCategories.categoryId, id));
    await db.delete(categories).where(eq(categories.id, id));
  }

  async getTags(): Promise<Tag[]> {
    try {
      const result = await db.select().from(tags);
      return Array.isArray(result) ? result : [];
    } catch (error) {
      console.error("Error fetching tags:", error);
      return [];
    }
  }

  async createTag(tag: InsertTag): Promise<Tag> {
