  async updateMedia(id: string, mediaItem: Partial<InsertMedia>): Promise<Media> {
    const [result] = await db.update(media)
      .set(mediaItem)
      .where(eq(media.id, id))
      .returning();
    return result;
  }

  async deleteMedia(id: string): Promise<void> {
